#include <iostream>
#include <string>

// Struct: groups related data together
struct Player {
    std::string name;
    int health;
    int attack;
    int defense;
    double gold;
};

struct Enemy {
    std::string name;
    int health;
    int damage;
    bool isBoss;
};

struct Item {
    std::string name;
    int value;
    std::string type;  // "weapon", "potion", "armor"
};

int main() {
    std::cout << "=== Structs in Action ===" << std::endl;

    // Create a Player struct instance
    Player hero;
    hero.name = "Hero";
    hero.health = 100;
    hero.attack = 15;
    hero.defense = 10;
    hero.gold = 50.0;

    std::cout << "Player Name: " << hero.name << std::endl;
    std::cout << "Health: " << hero.health << std::endl;
    std::cout << "Attack: " << hero.attack << std::endl;
    std::cout << "Defense: " << hero.defense << std::endl;
    std::cout << "Gold: $" << hero.gold << std::endl;

    // Create an Enemy struct
    Enemy goblin;
    goblin.name = "Goblin";
    goblin.health = 30;
    goblin.damage = 8;
    goblin.isBoss = false;

    std::cout << "\n=== Enemy Stats ===" << std::endl;
    std::cout << "Name: " << goblin.name << std::endl;
    std::cout << "Health: " << goblin.health << std::endl;
    std::cout << "Damage: " << goblin.damage << std::endl;
    std::cout << "Is Boss? " << (goblin.isBoss ? "Yes" : "No") << std::endl;

    // Array of structs
    Item inventory[3];
    inventory[0] = {"Iron Sword", 50, "weapon"};
    inventory[1] = {"Health Potion", 25, "potion"};
    inventory[2] = {"Leather Armor", 40, "armor"};

    std::cout << "\n=== Inventory ===" << std::endl;
    for (int i = 0; i < 3; i++) {
        std::cout << inventory[i].name << " (" << inventory[i].type 
                  << ") - Value: " << inventory[i].value << std::endl;
    }

    // Modifying struct fields
    hero.health -= 20;
    std::cout << "\nHero took damage! Health: " << hero.health << std::endl;

    return 0;
}

