#include <iostream>
#include <string>

struct Weapon {
    std::string name;
    int damage;
    int durability;
};

int main() {
    Weapon sword = {"Iron Sword", 15, 100};

    std::cout << "=== Weapon Stats ===" << std::endl;
    std::cout << "Name: " << sword.name << std::endl;
    std::cout << "Damage: " << sword.damage << std::endl;
    std::cout << "Durability: " << sword.durability << std::endl;

    sword.durability -= 10;
    std::cout << "\nAfter using the sword:" << std::endl;
    std::cout << "Durability: " << sword.durability << std::endl;

    Weapon bow = {"Longbow", 12, 80};

    std::cout << "\n=== Weapons ===" << std::endl;
    std::cout << "Sword: " << sword.name << " (Damage: " << sword.damage 
              << ", Durability: " << sword.durability << ")" << std::endl;
    std::cout << "Bow: " << bow.name << " (Damage: " << bow.damage 
              << ", Durability: " << bow.durability << ")" << std::endl;

    return 0;
}
